sp_angular_provider.script:
//! Do not remove dependency: spUtil
function scmNavFlyoverManager($rootScope, scmFlyover, $location, $httpParamSerializer, spUtil) {
    'use strict';

    const NAV_PREFIX = 'scm_nav';
    const UTILS_SCRIPT_NAME = 'x_680259_scm.NavigationManagerAJAX';

    let navConfigs = [];

    const locationParams = $location.search();
    let currentPage = locationParams.id;

    // Getting all configurations for the page from the server
    getConfigsFromServer();

    /*
        Init a flyover that will render widgets regarding the config.
        This object will be reused every time we need new content
    */
    const flyover = new scmFlyover('', $rootScope);
    flyover.setAppendToBody(true);

    /*
        Listen to every location change:
        - in case the "page id" has been changed, we need to re-load configs
        - in case URL params changed and we have a suitable config - we open a flyover
    */
    $rootScope.$on('$locationChangeStart', () => {
        runOnLocationChange();
    });

    // Pass accessible functions to the factory and return them
    const factory = {
        navigate: navigate,
        removeNavParams: removeNavParams
    };

    return factory;

    function runOnLocationChange() {
        // Check if page ID was changed. If so, load new configurations from server
        const params = $location.search();
        if (currentPage != params.id) {
            currentPage = params.id;
            getConfigsFromServer();
            return;
        }

        const navParams = getNavParams();

        // Do nothing if there is no param that should be handled by Navigation Manager
        if (!navParams[NAV_PREFIX]) return;

        const decodedNavParams = decodeNavParams(navParams);
        navConfigs
            .filter(config => config.name == navParams[NAV_PREFIX])
            // Only 1 config should be there after the filtering
            .forEach(config => {
                let title, options, beforeOpen;

                /*
                    Eval "before open". This script gets the result of the 
                    evaluation of the "Render condition" script from the server
                */
                (function (navParams, renderResponse) {
                    try {
                        beforeOpen = eval(config.beforeOpen);
                    } catch (error) {
                        console.error(
                            "Failed to evaluate 'Before open' script for config " + config.name + ': ' + error
                        );
                    }
                })(decodedNavParams, config.render);

                // Stop execution if "beforeOpen" script was evaluated to "false"
                if (!beforeOpen) return;

                // Eval "title" using navParams
                (function (navParams) {
                    try {
                        title = eval(config.title);
                    } catch (error) {
                        console.error("Failed to evaluate 'Title' script for config " + config.name + ': ' + error);
                    }
                })(decodedNavParams);

                // Eval "options" using navParams
                (function (navParams) {
                    try {
                        options = eval(config.options);
                    } catch (error) {
                        console.error("Failed to evaluate 'Options' script for config " + config.name + ': ' + error);
                    }
                })(decodedNavParams);

                // Open flyover with given configuration
                flyover.setTitle(title);
                flyover.setOptions(options);
                flyover.setWidgetId(config.widget_id);
                flyover.onClose(cleanupNavParams);
                flyover.open();
            });
    }

    function navigate(navOptions) {
        // If flyover is open, close it first. Then set new params
        if (flyover.isOpen()) {
            flyover
                .close()
                // Set new params when we sure flyover is closed
                .then(() => {
                    setParamsToUrl(navOptions);
                });
        } else {
            setParamsToUrl(navOptions);
        }
    }

    function setParamsToUrl(navOptions) {
        // Encode navigation options with prefix. Add "spa=1" to avoid page reload
        const navParams = encodeNavParams(navOptions);
        navParams.spa = 1;

        // Combine existing params with new navigation params
        const params = $location.search();
        angular.extend(params, navParams);

        // Set the new url params, so our listener can react on it
        $location.search($httpParamSerializer(params));
    }

    function removeNavParams(navOptionsToRemove) {
        const currentParams = $location.search();
        navOptionsToRemove.forEach(key => delete currentParams[key]);
        $location.search($httpParamSerializer(currentParams));
    }

    function getNavParams() {
        const params = $location.search();
        return Object.keys(params)
            .filter(key => key.startsWith(NAV_PREFIX))
            .reduce((cur, key) => {
                return Object.assign(cur, { [key]: params[key] });
            }, {});
    }

    function cleanupNavParams() {
        const currentParams = $location.search();
        const currentNavParams = getNavParams();
        Object.keys(currentNavParams).forEach(key => delete currentParams[key]);
        $location.search($httpParamSerializer(currentParams));
    }

    function encodeNavParams(params) {
        const encodedParams = {};
        Object.keys(params).forEach(param => {
            if (param == 'name') {
                encodedParams[NAV_PREFIX] = params[param];
            } else {
                encodedParams[NAV_PREFIX + '_' + param] = params[param];
            }
        });
        return encodedParams;
    }

    function decodeNavParams(params) {
        const decodedParams = {};
        Object.keys(params).forEach(param => {
            if (param == NAV_PREFIX) {
                decodedParams['name'] = params[param];
            } else {
                decodedParams[param.slice(NAV_PREFIX.length + 1)] = params[param];
            }
        });
        return decodedParams;
    }

    function getConfigsFromServer() {
        const locationParams = $location.search();
        if (!locationParams.id) {
            navConfigs = scm_scratchpad.navigationConfigs = [];
            return;
        }
        scm_scratchpad
            .glideAjax(UTILS_SCRIPT_NAME, 'getPageConfigs', {
                page: locationParams.id,
                params: JSON.stringify(locationParams)
            })
            .then(function (configs) {
                /*
                    Configs are exposed to the global variable 
                    scm_scratchpad.navigationConfigs for debugging purposes
                */
                navConfigs = scm_scratchpad.navigationConfigs = JSON.parse(configs);
                runOnLocationChange();
            });
    }
}
